DNS module provides asynchronous DNS resolution and domain name utilities in Node.js.

**Basic DNS Resolution**:
```javascript
const dns = require('dns');

// Resolve domain to IP addresses
dns.resolve('google.com', (err, addresses) => {
  if (err) throw err;
  console.log('IP addresses:', addresses);
});

// Resolve IPv4 addresses only
dns.resolve4('google.com', (err, addresses) => {
  if (err) throw err;
  console.log('IPv4 addresses:', addresses);
});

// Resolve IPv6 addresses only
dns.resolve6('google.com', (err, addresses) => {
  if (err) throw err;
  console.log('IPv6 addresses:', addresses);
});
```

**Reverse DNS Lookup**:
```javascript
// IP address to domain name
dns.reverse('8.8.8.8', (err, hostnames) => {
  if (err) throw err;
  console.log('Hostnames:', hostnames);
});
```

**DNS Record Types**:
```javascript
// MX records (mail exchange)
dns.resolveMx('google.com', (err, addresses) => {
  if (err) throw err;
  console.log('MX records:', addresses);
});

// TXT records
dns.resolveTxt('google.com', (err, records) => {
  if (err) throw err;
  console.log('TXT records:', records);
});

// SRV records (service)
dns.resolveSrv('_http._tcp.google.com', (err, addresses) => {
  if (err) throw err;
  console.log('SRV records:', addresses);
});

// NS records (name servers)
dns.resolveNs('google.com', (err, addresses) => {
  if (err) throw err;
  console.log('NS records:', addresses);
});
```

**Promise-based API**:
```javascript
const dns = require('dns').promises;

async function lookupDomain() {
  try {
    const addresses = await dns.resolve4('google.com');
    console.log('IPv4 addresses:', addresses);

    const mx = await dns.resolveMx('google.com');
    console.log('MX records:', mx);

    const txt = await dns.resolveTxt('google.com');
    console.log('TXT records:', txt);
  } catch (err) {
    console.error('DNS lookup failed:', err);
  }
}
```

**DNS Lookup Options**:
